// Chat Store
export const useChatStore = create(
  persist(
    (set, get) => ({
      conversations: [] as any[],
      activeConversationId: null as string | null,
      messages: [] as any[],
      isStreaming: false,
      addConversation: (title?: string) => {
        const id = crypto.randomUUID();
        set((s: any) => ({
          conversations: [
            { id, title: title || "New Chat", createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), pinned: false },
            ...s.conversations,
          ],
          activeConversationId: id,
          messages: [],
        }));
        return id;
      },
      setActiveConversationId: (id: string | null) => {
        set({ activeConversationId: id, messages: [] });
      },
      setConversations: (convs: any[]) => set({ conversations: convs }),
      setMessages: (msgs: any[]) => set({ messages: msgs }),
      removeConversation: (id: string) => set((s: any) => ({
        conversations: s.conversations.filter((c: any) => c.id !== id),
        activeConversationId: s.activeConversationId === id ? null : s.activeConversationId,
        messages: s.activeConversationId === id ? [] : s.messages,
      })),
      updateConversation: (id: string, data: any) => set((s: any) => ({
        conversations: s.conversations.map((c: any) => (c.id === id ? { ...c, ...data, updatedAt: new Date().toISOString() } : c)),
      })),
      sendMessage: async (formData: FormData) => {
        set({ isStreaming: true });
        try {
          const res = await fetch("/api/chat", {
            method: "POST",
            body: formData,
          });
          if (!res.ok) throw new Error(`HTTP ${res.status}`);

          const reader = res.body?.getReader();
          const decoder = new TextDecoder();
          let buffer = "";
          let fullResponse = "";

          while (reader) {
            const { done, value } = await reader.read();
            if (done) break;

            buffer += decoder.decode(value, { stream: true });
            const lines = buffer.split("\n");
            buffer = lines.pop() || "";

            for (const line of lines) {
              if (line.startsWith("data: ")) {
                const data = line.slice(6).trim();
                if (data === "[DONE]") continue;
                try {
                  const parsed = JSON.parse(data);
                  if (parsed.content) {
                    fullResponse += parsed.content;
                    set((s: any) => {
                      const msgs = [...s.messages];
                      const lastMsg = msgs[msgs.length - 1];
                      if (lastMsg && lastMsg.role === "assistant") {
                        msgs[msgs.length - 1] = { ...lastMsg, content: fullResponse };
                      } else {
                        msgs.push({ id: parsed.messageId || crypto.randomUUID(), role: "assistant", content: parsed.content, createdAt: new Date().toISOString() });
                      }
                      return { messages: msgs };
                    });
                  }
                  if (parsed.conversationId) {
                    set((s: any) => {
                      if (s.activeConversationId !== parsed.conversationId) {
                        return { activeConversationId: parsed.conversationId };
                      }
                      return {};
                    });
                  }
                } catch {}
              }
            }
          }
        } catch (err: any) {
          if (err.name !== "AbortError") {
            console.error("Send error:", err);
          }
        } finally {
          set({ isStreaming: false });
        }
      },
      stopStreaming: () => {
        set({ isStreaming: false });
      },
      regenerateMessage: async (messageId: string) => {
        // For now, just a stub
      },
    }),
    { name: "clawhub-chat" }
  )
);

