import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function GET() {
  try {
    const conversations = await prisma.conversation.findMany({
      orderBy: { updatedAt: "desc" },
      include: {
        messages: {
          orderBy: { createdAt: "asc" },
        },
      },
    });

    // Format for export
    const exportData = conversations.map((conv: { id: any; title: any; model: any; systemPrompt: any; createdAt: any; updatedAt: any; agentId: any; messages: any[]; }) => ({
      id: conv.id,
      title: conv.title,
      model: conv.model,
      systemPrompt: conv.systemPrompt,
      createdAt: conv.createdAt,
      updatedAt: conv.updatedAt,
      agentId: conv.agentId,
      messages: conv.messages.map((msg: { id: any; role: any; content: any; files: any; thinking: any; toolCalls: any; createdAt: any; }) => ({
        id: msg.id,
        role: msg.role,
        content: msg.content,
        attachments: msg.files,
        thinking: msg.thinking,
        toolCalls: msg.toolCalls,
        createdAt: msg.createdAt,
      })),
    }));

    return new Response(JSON.stringify(exportData, null, 2), {
      headers: {
        "Content-Type": "application/json",
        "Content-Disposition": `attachment; filename="clawhub-export-${new Date().toISOString().split("T")[0]}.json"`,
      },
    });
