          if (!apiKey) throw new Error("Anthropic API key not configured");

          const client = new Anthropic({ apiKey });
          const response = await client.messages.create({
            model: model || "claude-3-7-sonnet-20250219",
            system: systemPrompt,
            max_tokens: 8192,
            messages: [{ role: "user", content: [{ type: "text", text: content }] }],
            stream: true,
          });

          for await (const event of response) {
            if (event.type === "content_block_delta" && "text" in event.delta) {
              const text = event.delta.text;
              fullResponse += text;
              controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content: text, conversationId: convId })}\n\n`));
            }
            if (event.type === "content_block_delta" && "thinking" in event.delta) {
              thinkingText += (event.delta as any).thinking || "";
            }
          }
        } else if (provider === "groq") {
          const apiKey = settings?.providers?.groq?.apiKey || process.env.GROQ_API_KEY;
          if (!apiKey) throw new Error("Groq API key not configured");

          const client = new Groq({ apiKey });
          const response = await client.chat.completions.create({
            model: model || "llama-3.3-70b-versatile",
            messages: [
