            ],
            stream: true,
            temperature: 0.7,
          });

          for await (const chunk of response) {
            const text = chunk.choices?.[0]?.delta?.content;
            if (text) {
              fullResponse += text;
              controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content: text, conversationId: convId })}\n\n`));
            }
          }
        } else if (provider === "ollama") {
