          const response = await fetch(`${baseUrl}/api/chat`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              model: model || "llama3",
              messages: [
                { role: "system", content: systemPrompt },
                { role: "user", content },
              ],
              stream: true,
            }),
          });

          const reader = response.body?.getReader();
          if (!reader) throw new Error("No response body");

          const decoder = new TextDecoder();
          while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            const lines = decoder.decode(value).split("\n").filter(Boolean);
            for (const line of lines) {
              try {
                const json = JSON.parse(line);
                if (json.message?.content) {
                  fullResponse += json.message.content;
                  controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content: json.message.content, conversationId: convId })}\n\n`));
                }
              } catch {}
            }
          }
        }

        // Save assistant message
        await prisma.message.create({
          data: {
            content: fullResponse,
            role: "assistant",
            conversationId: convId,
            agentId: agentId || null,
            thinking: thinkingText || undefined,
          },
        });

        controller.enqueue(encoder.encode("data: [DONE]\n\n"));
      } catch (err: any) {
        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ error: err.message || "Stream failed" })}\n\n`));
      } finally {
        activeStreams.delete(streamId);
        controller.close();
      }
    },
    cancel() {
      const aborter = activeStreams.get(streamId);
      if (aborter) aborter.abort();
      activeStreams.delete(streamId);
    },
  });

